mapper.select:
SELECT m.milestone_id, m.project_id, m.user_code, m.milestone_title, m.milestone_describe, m.finish_date, m.milestone_status AS milestone_status, m.created_at, m.updated_at,
NVL(stats.total_count, 0) AS total_task_count, NVL(stats.closed_count, 0) AS closed_task_count, NVL(stats.avg_progress, 0) AS progress_percentage, CASE WHEN NVL(stats.avg_progress, 0) < 100 AND TRUNC(SYSDATE) > TRUNC(m.finish_date) THEN TRUNC(SYSDATE) - TRUNC(m.finish_date) ELSE 0 END AS delay_days,
NVL(stats.total_estimated, 0) AS total_estimated_hours, NVL(stats.total_spent, 0) AS total_spent_hours FROM milestone m LEFT JOIN ( SELECT milestone_id, COUNT(*) AS total_count, SUM(CASE WHEN task_status = 'e3' THEN 1 ELSE 0 END) AS closed_count, ROUND(AVG(NVL(task_progress, 0))) AS avg_progress, SUM(NVL(estimated_time, 0)) AS total_estimated, SUM(NVL(spent_hours_sum, 0)) AS total_spent FROM task WHERE milestone_id = #{milestoneId} AND project_id = #{projectId} AND deleted_yn = 'N' GROUP BY milestone_id ) stats ON m.milestone_id = stats.milestone_id WHERE m.milestone_id = #{milestoneId} AND m.project_id = #{projectId}

SELECT p.project_id, p.project_title, p.project_describe, p.created_at, p.finish_date, CASE WHEN p.finish_date IS NOT NULL AND p.finish_date <= TRUNC(SYSDATE) THEN '완료'
WHEN EXISTS ( SELECT 1 FROM task t WHERE t.project_id = p.project_id ) THEN '진행 중'
ELSE '신규' END AS status FROM project p WHERE p.project_id = #{projectId}

