mapper.select:
SELECT COUNT(*)
FROM task t
LEFT OUTER JOIN users u      ON t.task_manager = u.user_code
LEFT OUTER JOIN task_types tt ON t.type_id = tt.type_id
WHERE t.project_id = #{projectId} AND t.deleted_yn = 'N'
  AND (t.milestone_id IS NULL 

      OR t.milestone_id = #{milestoneId}
      )

  AND t.task_status = #{taskStatus}


  AND t.priority = #{priority}


  AND u.user_name = #{taskManager}


  AND t.type_id = #{typeId}

SELECT * FROM (
    SELECT a.*, ROWNUM AS rnum FROM (
        SELECT 
            t.task_id          AS taskId,
            t.task_title       AS taskTitle,
            t.task_describe    AS taskDescribe,
            t.task_status      AS taskStatus,
            t.priority         AS priority,
            u.user_name        AS taskManager,   
            tt.type_name       AS typeName,
            t.start_date       AS startDate,
            t.finish_date      AS finishDate,
            t.task_progress    AS taskProgress,
            t.project_id       AS projectId,
            t.milestone_id     AS milestoneId
        FROM task t
        LEFT OUTER JOIN users u      ON t.task_manager = u.user_code
        LEFT OUTER JOIN task_types tt ON t.type_id = tt.type_id
        WHERE t.project_id = #{projectId} AND t.deleted_yn = 'N'
          AND (t.milestone_id IS NULL 

              OR t.milestone_id = #{milestoneId}
              )

          AND t.task_status = #{taskStatus}


          AND t.priority = #{priority}


          AND u.user_name = #{taskManager}


          AND t.type_id = #{typeId}

        ORDER BY t.created_at DESC
    ) a WHERE ROWNUM <= #{endRow}
) WHERE rnum >= #{startRow}

SELECT COUNT(*)
FROM members
WHERE PROJECT_ID = #{projectId}
  AND USER_CODE = #{userCode}
